document.addEventListener("DOMContentLoaded",(()=>{fetch("../assets/data/trips/vietnam.json").then((n=>n.json())).then((n=>{const e=document.querySelector("main");n.days.forEach((n=>{const t=document.createElement("div");t.classList.add("day");const i=document.createElement("h2");i.classList.add("day-header"),i.innerText=n.day,t.appendChild(i);const c=document.createElement("div");c.classList.add("day-content"),n.checkpoints.forEach((n=>{let e;n.link?(e=document.createElement("a"),e.href=n.link,e.target="_blank"):e=document.createElement("div"),e.classList.add("day-content-checkpoint"),n.class&&e.classList.add(n.class);let t="";n.infos&&n.infos.forEach((n=>{t+=`\n              <div class="day-content-checkpoint-info-infos-item">\n              ${n.icon?`<i class="fa-solid ${n.icon}"></i>`:""} ${n.text}\n              </div>\n              `}));const i=`\n          <div class="day-content-checkpoint-timeline">\n            <div class="day-content-checkpoint-timeline-time">${n.time}</div>\n              <div class="day-content-checkpoint-timeline-line"></div>\n            </div>\n            <div class="day-content-checkpoint-info">\n              <div class="day-content-checkpoint-info-title">\n                ${n.icon?`<i class="fa-solid ${n.icon}"></i>`:""} ${n.title}\n              </div>\n              ${n.description?`<div class="day-content-checkpoint-info-description">${n.description}</div>`:""}\n              ${t?`<div class="day-content-checkpoint-info-infos">${t}</div>`:""}\n          </div>\n          `;e.innerHTML=i,c.appendChild(e)})),t.appendChild(c),e.appendChild(t),i.addEventListener("click",(()=>{c.classList.toggle("expanded")}))}))})).catch((n=>console.error("Error loading itinerary:",n))),fetch("https://api.weatherapi.com/v1/current.json?key=0bc7f2f831a14bf8b93154800240707&q=Danang&aqi=no").then((n=>n.json())).then((n=>{document.getElementById("weather-info").innerHTML=`\n<div class="weather-item"><i class="fas fa-thermometer-half"></i> ${n.current.temp_c} °C</div>\n<div class="weather-item"><i class="fas fa-cloud"></i> ${n.current.condition.text}</div>\n<div class="weather-item"><i class="fas fa-tint"></i> ${n.current.humidity}%</div>\n<div class="weather-item"><i class="fas fa-wind"></i> ${n.current.wind_kph} kph</div>\n`})).catch((n=>console.error("Error fetching weather data:",n)))}));